export interface DebounceOptions { leading?: boolean; trailing?: boolean; }
export interface DebouncedFn<T extends (...a: any[]) => any> {
  (...args: Parameters<T>): void;
  cancel: () => void;
  flush: () => void;
}
export function debounce<T extends (...a: any[]) => any>(fn: T, ms: number, opts: DebounceOptions = {}): DebouncedFn<T> {
  const { leading = false, trailing = true } = opts;
  let t: ReturnType<typeof setTimeout> | null = null;
  let lastArgs: Parameters<T> | null = null;
  const debounced = ((...args) => {
    lastArgs = args;
    if (leading && !t) fn(...args);
    if (t) clearTimeout(t);
    t = setTimeout(() => { if (trailing && lastArgs) fn(...lastArgs); t = null; lastArgs = null; }, ms);
  }) as DebouncedFn<T>;
  debounced.cancel = () => { if (t) { clearTimeout(t); t = null; } };
  debounced.flush = () => { if (t && lastArgs) { clearTimeout(t); fn(...lastArgs); t = null; lastArgs = null; } };
  return debounced;
}
